-- 标记所有文本块为已处理（全文检索模式）
UPDATE material_chunks SET vectorId = 'fulltext' WHERE vectorId IS NULL OR vectorId = '';

-- 将所有教材状态改为已发布，并更新 totalChunks
UPDATE materials m 
SET m.status = 'published', 
    m.totalChunks = (SELECT COUNT(*) FROM material_chunks mc WHERE mc.materialId = m.id)
WHERE m.status IN ('processing', 'error', 'pending');

-- 查看结果
SELECT id, title, status, totalChunks FROM materials;
SELECT COUNT(*) as total_chunks, COUNT(CASE WHEN vectorId = 'fulltext' THEN 1 END) as processed_chunks FROM material_chunks;

